+    function activateTab(tab) {
+      tabs.forEach(btn => {
+        const selected = btn === tab;
+        btn.setAttribute('aria-selected', String(selected));
+      });
+      panels.forEach(panel => {
+        panel.hidden = panel.id !== tab.getAttribute('aria-controls');
+      });
