            candidate = base / rel
            if candidate.is_file():
                return candidate
    url = row.get("image_url")
    sid = row.get("snippet_id") or "snippet"
    if not url:
        return None
    dest = raw_dir / "images" / f"{sid}.jpg"
    if dest.is_file() and dest.stat().st_size > 1000:
