def _image_url(pack: CluePack) -> str | None:
    path = resolve_image(pack)
    if not path:
        return None
    rel = pack.fragment.image_path
    if rel and rel.startswith("assets/"):
        return f"/{rel}"
    return None


def pack_to_dict(pack: CluePack, *, show_reveal: bool) -> dict:
    return {
        "artifact_id": pack.artifact_id,
        "beat_intro": pack.beat_intro,
        "mystery_score": pack.mystery_score,
        "mystery_tier": (
            "cold" if pack.mystery_score < 0.4 else "warm" if pack.mystery_score < 0.7 else "hot"
        ),
        "source": {
            "publication": pack.source.publication,
            "date": pack.source.date,
            "archive": pack.source.archive,
            "citation_url": pack.source.citation_url,
        },
        "image_url": _image_url(pack),
        "raw_ocr": pack.fragment.raw_ocr,
        "clean_text": pack.fragment.clean_text,
        "entities": [e.model_dump() for e in pack.entities],
        "evidence_cards": [c.model_dump() for c in pack.evidence_cards],
        "clue_types": pack.clue_types,
        "evidence_md": format_evidence(pack),
        "leads": [{"id": l.id, "label": l.label} for l in pack.lead_options],
        "reveal": format_reveal(pack) if show_reveal else None,
        "model_reading": {
            "artifact_id": pack.artifact_id,
            "mystery_score": pack.mystery_score,
            "clue_types": pack.clue_types,
            "entities": [e.model_dump() for e in pack.entities],
            "evidence_cards": [c.model_dump() for c in pack.evidence_cards],
            "reveal_notes": pack.reveal_notes.model_dump(),
        },
    }


def session_to_dict(session: CaseSession, *, show_reveal: bool) -> dict:
    return {
        "case_id": session.case.case_id,
        "title": session.case.title,
        "tagline": session.case.tagline,
        "beat_id": session.beat_id,
        "terminal": session.is_terminal(),
        "history": [{"beat": b, "label": label} for b, label in session.history],
        "pack": pack_to_dict(session.pack, show_reveal=show_reveal),
    }


@dataclass
class SessionStore:
    """In-memory sessions for the Server API."""

    _sessions: dict[str, CaseSession] = field(default_factory=dict)

    def create(self, case_id: str) -> tuple[str, CaseSession]:
        import secrets

        sid = secrets.token_hex(12)
        session = start_session(case_id)
        self._sessions[sid] = session
        return sid, session

    def get(self, session_id: str) -> CaseSession | None:
        return self._sessions.get(session_id)

    def reset(self, session_id: str, case_id: str) -> CaseSession | None:
        if session_id not in self._sessions:
            return None
        session = start_session(case_id)
        self._sessions[session_id] = session
        return session

"""Custom frontend via gradio.Server (Off-Brand badge path)."""

from __future__ import annotations

from pathlib import Path

from fastapi.responses import FileResponse
from fastapi.staticfiles import StaticFiles
from gradio import Server

from archive_detective.api import SessionStore, list_case_catalog, session_to_dict

ROOT = Path(__file__).resolve().parents[2]
STATIC = Path(__file__).resolve().parent / "static" / "board"
ASSETS = ROOT / "assets"

store = SessionStore()


def build_server() -> Server:
    app = Server(title="Archive Detective")

    @app.get("/")
    async def home():
        return FileResponse(STATIC / "index.html")

    @app.get("/board.css")
    async def board_css():
        return FileResponse(STATIC / "board.css", media_type="text/css")

    @app.get("/board.js")
    async def board_js():
        return FileResponse(STATIC / "board.js", media_type="application/javascript")

    if ASSETS.is_dir():
        app.mount("/assets", StaticFiles(directory=str(ASSETS)), name="assets")

    @app.api(name="catalog")
    def catalog() -> list[dict]:
        return list_case_catalog()

    @app.api(name="start_case")
    def start_case(case_id: str) -> dict:
        sid, session = store.create(case_id)
        return {"session_id": sid, **session_to_dict(session, show_reveal=False)}

    @app.api(name="reset_case")
    def reset_case(session_id: str, case_id: str) -> dict:
        session = store.reset(session_id, case_id)
        if session is None:
            sid, session = store.create(case_id)
            return {"session_id": sid, **session_to_dict(session, show_reveal=False)}
        return {"session_id": session_id, **session_to_dict(session, show_reveal=False)}

    @app.api(name="choose_lead")
    def choose_lead(session_id: str, lead_id: str) -> dict:
        session = store.get(session_id)
        if session is None:
            raise ValueError("Session expired — reload the case.")
        session.choose_lead(lead_id)
        return {"session_id": session_id, **session_to_dict(session, show_reveal=False)}

    @app.api(name="reveal")
    def reveal(session_id: str) -> dict:
        session = store.get(session_id)
        if session is None:
            raise ValueError("Session expired — reload the case.")
        session.revealed = True
        return {"session_id": session_id, **session_to_dict(session, show_reveal=True)}

    return app


def launch(**kwargs) -> None:
    defaults = {
        "server_name": "127.0.0.1",
        "server_port": 7860,
        "show_error": True,
        "footer_links": None,
    }
    defaults.update(kwargs)
    url = f"http://{defaults['server_name']}:{defaults['server_port']}/"
    print(f"\nArchive Detective (custom board) → {url}\n")
    build_server().launch(**defaults)

