/** Archive Detective board — calls gradio.Server APIs */

async function callApi(name, ...args) {
  const res = await fetch(`/gradio_api/call/${name}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ data: args }),
  });
  if (!res.ok) {
    throw new Error(`API ${name} failed (${res.status})`);
  }
  const envelope = await res.json();
  const eventId = envelope.event_id;
  if (!eventId) {
    throw new Error(`No event_id from ${name}`);
  }
  // Poll for result (Gradio queue)
  for (let i = 0; i < 120; i++) {
    await new Promise((r) => setTimeout(r, 50));
    const poll = await fetch(`/gradio_api/call/${name}/${eventId}`);
    if (!poll.ok) continue;
    const body = await poll.json();
    if (body.status === "COMPLETE") {
      const data = body.output?.data;
      return data?.length === 1 ? data[0] : data;
    }
    if (body.status === "FAILED") {
      throw new Error(body.output?.error || `${name} failed`);
    }
  }
  throw new Error(`${name} timed out`);
}

const $ = (id) => document.getElementById(id);

let sessionId = null;
let catalog = [];

function showError(msg) {
  const el = $("error");
  el.hidden = false;
  el.textContent = msg;
}

function clearError() {
  $("error").hidden = true;
}

function renderMarkdownish(text) {
  if (!text) return "";
  return text
    .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
    .replace(/\n/g, "<br/>");
}

function renderState(state) {
  clearError();
  $("board").hidden = false;
  $("loading").hidden = true;

  $("case-title").textContent = state.title;
  $("case-tagline").textContent = state.tagline;

  const pack = state.pack;
  const badge = $("mystery-badge");
  badge.textContent = `${pack.mystery_tier} · mystery ${Math.round(pack.mystery_score * 100)}%`;
  badge.className = `mystery-badge ${pack.mystery_tier}`;

  $("beat-intro").textContent = pack.beat_intro;

  const src = pack.source;
  $("source-line").textContent = `${src.publication} · ${src.date}`;
  $("clipping-caption").textContent = `${src.publication}, ${src.date}`;

  const img = $("clipping-img");
  if (pack.image_url) {
    img.src = pack.image_url;
    img.hidden = false;
  } else {
    img.removeAttribute("src");
    img.hidden = true;
  }

  $("raw-ocr").textContent = pack.raw_ocr || "(none)";
  $("clean-text").textContent = pack.clean_text || "(none)";
  $("clue-types").textContent = pack.clue_types?.join(", ") || "";

  const stack = $("evidence-stack");
  stack.innerHTML = "";
  if (!pack.evidence_cards?.length) {
    stack.innerHTML = '<p class="hint">No evidence cards pinned yet.</p>';
  } else {
    for (const card of pack.evidence_cards) {
      const el = document.createElement("article");
      el.className = "evidence-card";
      el.innerHTML = `<div class="type">${card.clue_type}</div><h3>${card.title}</h3><p>${card.detail}</p>`;
      stack.appendChild(el);
    }
  }

  const rail = $("entity-rail");
  rail.innerHTML = "";
  for (const ent of pack.entities || []) {
    const tag = document.createElement("span");
    tag.className = "entity-tag";
    tag.innerHTML = `<em>${ent.type}</em>${ent.value}`;
    rail.appendChild(tag);
  }

  const leads = $("lead-buttons");
  leads.innerHTML = "";
  for (const lead of pack.leads || []) {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "btn lead";
    btn.textContent = lead.label;
    btn.addEventListener("click", () => onLead(lead.id));
    leads.appendChild(btn);
  }

  const trail = state.history?.length
    ? state.history.map((h) => `${h.beat}: ${h.label}`).join(" → ")
    : "";
  $("trail").textContent = trail ? `Trail · ${trail}` : "";

  const reveal = $("reveal-panel");
  if (pack.reveal) {
    reveal.hidden = false;
    reveal.innerHTML = renderMarkdownish(pack.reveal);
  } else {
    reveal.hidden = true;
    reveal.innerHTML = "";
  }

  $("model-reading").textContent = JSON.stringify(pack.model_reading, null, 2);
}

async function loadCatalog() {
  catalog = await callApi("catalog");
  const sel = $("case-select");
  sel.innerHTML = "";
  for (const c of catalog) {
    const opt = document.createElement("option");
    opt.value = c.id;
    opt.textContent = c.title;
    sel.appendChild(opt);
  }
}

async function startCase(caseId) {
  $("loading").hidden = false;
  $("board").hidden = true;
  const state = await callApi("start_case", caseId);
  sessionId = state.session_id;
  renderState(state);
}

async function onLead(leadId) {
  if (!sessionId) return;
  const state = await callApi("choose_lead", sessionId, leadId);
  renderState(state);
}

async function onReveal() {
  if (!sessionId) return;
  const state = await callApi("reveal", sessionId);
  renderState(state);
}

async function init() {
  try {
    await loadCatalog();
    const sel = $("case-select");
    sel.addEventListener("change", () => startCase(sel.value));
    $("btn-reset").addEventListener("click", () => startCase(sel.value));
    $("btn-reveal").addEventListener("click", onReveal);
    if (catalog.length) {
      await startCase(catalog[0].id);
    }
  } catch (err) {
    $("loading").hidden = true;
    showError(err.message || String(err));
  }
}

init();

